document.addEventListener("DOMContentLoaded",(function(event){const orders=document.querySelector(".orders--slider");if(orders&&"function"==typeof initSwiperSlider){initSwiperSlider();let resizeTimer=!1;window.onresize=function(event){orders.classList.contains("swiper--hidden-on-resize")&&(resizeTimer?clearTimeout(resizeTimer):orders.querySelectorAll(".swiper-slide").forEach(slide=>{slide.style.maxWidth=slide.style.minWidth=slide.clientWidth+"px"}),resizeTimer=setTimeout((function(){resizeTimer=!1,orders.querySelectorAll(".swiper-slide").forEach(slide=>{slide.style.maxWidth=slide.style.minWidth=""}),setTimeout((function(){orders.swiper.update(),orders.swiper.slideTo(0)}),0)}),100))}}}));